import traceback
from src.rag.retriever import Retriever


def main():
    retriever = Retriever()
    print("PHASE 1: VECTOR ENTRY POINT")
    vec_results = retriever.search_by_vector(vector, limit=1)
    if not vec_results:
        print("FAILED: No vector match.")
        return

    seed = vec_results[0]
    seed_id = seed['tmdbId']
    print(f"Entry Point: {seed.get('title')} (ID: {seed_id})\n")

    print("PHASE 2: ALL EXPLICIT GRAPH CONNECTIONS")
    connections = retriever.get_all_connected_data(seed_id)

    print(f"{'RELATIONSHIP':<20} | {'TYPE':<10} | {'DETAILS'}")
    print("-" * 100)

    for conn in connections:
        rel = conn['relationship']
        n_type = conn['type']
        data = conn['data']

        if n_type == 'Person':
            details = f"Name: {data.get('name')}, Job: {data.get('job', 'Actor')}"
        elif n_type == 'Genre':
            details = f"Genre: {data.get('genre_name')}"
        else:
            details = str(data)

        print(f"{rel:<20} | {n_type:<10} | {details}")
        print(f"\nTotal Connections: {len(connections)}\n")

        print("PHASE 3: RERANKED GRAPH RECOMMENDATIONS Top 5")
        recs = retriever.find_recommendations_by_graph(seed_id, query_vector=vector, depth=2, limit=5)

        for i, r in enumerate(recs, 1):
            print(f"  {i}. {r.get('title'):<30} | Score: {r.get('score'):.4f} | ID: {r.get('tmdbId')}")

        print("PHASE 4: HYBRID SEARCH FACADE CHECK")
        hybrid = retriever.hybrid_search(vector)
        if hybrid:
            h_seed = hybrid.get('seed_movie', {})
            h_recs = hybrid.get('graph_recommendations', [])
            h_context = hybrid.get('direct_connections', [])

            print(f"Hybrid Seed:      {h_seed.get('title') or h_seed.get('original_title')}")
            print(f"Context Entities: {len(h_context)}")
            print(f"Recs Found:       {len(h_recs)}")
        else:
            print("Hybrid search returned None.")


if __name__ == "__main__":
    main()